import Container from "../ui/Container.astro";
import AnimatedCard from "./AnimatedCard";
import { SERVICE_CARDS } from "../../lib/constants";
import { Briefcase, Heart, GraduationCap } from "lucide-react";

interface Props {
  class?: string;
}

const { class: className } = Astro.props;

// Map icon names to components
const iconMap = {
  Briefcase,
  Heart,
  GraduationCap,
};
---

<section id="services" class:list={["py-16 md:py-24 bg-white", className]}>
  <Container>
    <div class="text-center mb-12">
      <h2 class="text-2xl md:text-3xl lg:text-4xl font-bold text-neutral-900 mb-4">
        サービス紹介
      </h2>
      <p class="text-neutral-600 max-w-2xl mx-auto">
        仕事と介護の両立に関するあらゆるお悩みに対応します
      </p>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-3 gap-6 lg:gap-8">
      {SERVICE_CARDS.map((service, index) => (
        <AnimatedCard
          client:idle
          title={service.title}
          description={service.description}
          href={service.href}
          icon={service.icon}
          delay={index * 0.1}
        />
      ))}
    </div>
  </Container>
</section>
```

2. Create src/components/sections/AnimatedCard.tsx:

```tsx
import { useRef, useEffect } from "react";
import { inView, animate } from "motion";
import { Briefcase, Heart, GraduationCap, ArrowRight } from "lucide-react";

interface AnimatedCardProps {
  title: string;
  description: string;
  href: string;
  icon: string;
  delay?: number;
}

const iconComponents: Record<string, React.ComponentType<{ className?: string }>> = {
  Briefcase,
  Heart,
  GraduationCap,
};

export default function AnimatedCard({
  title,
  description,
  href,
  icon,
  delay = 0,
}: AnimatedCardProps) {
  const cardRef = useRef<HTMLAnchorElement>(null);
  const IconComponent = iconComponents[icon] || Briefcase;

  useEffect(() => {
    const card = cardRef.current;
    if (!card) return;

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (prefersReducedMotion) {
      card.style.opacity = "1";
      return;
    }

    // Set initial state
    card.style.opacity = "0";
    card.style.transform = "translateY(30px)";

    const cleanup = inView(
      card,
      () => {
        animate(
          card,
          { opacity: [0, 1], y: [30, 0] },
          {
            duration: 0.5,
            easing: [0.4, 0, 0.2, 1],
            delay,
          }
        );
      },
      { amount: 0.2 }
    );

    return cleanup;
  }, [delay]);

  return (
    <a
      ref={cardRef}
      href={href}
      className="group block bg-white rounded-2xl p-6 md:p-8 shadow-sm border border-neutral-100 hover:shadow-lg hover:border-sakura-200 transition-all duration-300 hover:-translate-y-1"
    >
      {/* Icon */}
      <div className="w-14 h-14 rounded-xl bg-sakura-50 flex items-center justify-center mb-6 group-hover:bg-sakura-100 transition-colors">
        <IconComponent className="w-7 h-7 text-sakura-600" />
      </div>

      {/* Content */}
      <h3 className="text-xl font-bold text-neutral-900 mb-3 group-hover:text-sakura-600 transition-colors">
        {title}
      </h3>
      <p className="text-neutral-600 text-sm leading-relaxed mb-4">
        {description}
      </p>

      {/* Link */}
      <div className="flex items-center text-sakura-600 font-medium text-sm">
        <span>詳しく見る</span>
        <ArrowRight className="w-4 h-4 ml-1 group-hover:translate-x-1 transition-transform" />
      </div>
    </a>
  );
}
```

